const fmt = (value: number, digits = 2) => {
  if (!Number.isFinite(value)) return "Invalid";
  return Number(value.toFixed(digits)).toLocaleString(undefined, { maximumFractionDigits: digits });
};

const sci = (value: number, digits = 3) => {
  if (!Number.isFinite(value)) return "Invalid";
  if (Math.abs(value) >= 100000 || (Math.abs(value) > 0 && Math.abs(value) < 0.01)) return value.toExponential(digits);
  return fmt(value, digits);
};

function forceTable() {
  const masses = [1, 5, 10, 50, 100, 500, 1000];
  const accels = [1, 5, 10, 20, 50];
  return masses.map((mass) => [`${mass} kg`, ...accels.map((a) => `${fmt(mass * a, 0)} N`)]);
}

function kineticTable() {
  const rows = [
    [1, "1 kg"],
    [5, "5 kg"],
    [10, "10 kg"],
    [50, "50 kg"],
    [100, "100 kg"],
    [1000, "1000 kg (car)"],
    [80000, "80000 kg (truck)"],
  ];
  const speeds = [1, 5, 10, 20, 100];
  return rows.map(([mass, label]) => [String(label), ...speeds.map((v) => `${sci(0.5 * Number(mass) * v * v, 2)} J`)]);
}

function potentialTable() {
  const rows = [
    [1, "1 kg"],
    [5, "5 kg"],
    [10, "10 kg"],
    [50, "50 kg"],
    [80, "80 kg (person)"],
    [1000, "1000 kg (car)"],
  ];
  const heights = [1, 5, 10, 100, 1000];
  return rows.map(([mass, label]) => [String(label), ...heights.map((h) => `${sci(Number(mass) * 9.81 * h, 2)} J`)]);
}

function applianceTable() {
  const rows = [
    ["LED bulb", 10],
    ["Phone charger", 15],
    ["Laptop", 60],
    ["TV", 120],
    ["Refrigerator", 150],
    ["Air conditioner", 1500],
    ["Electric car charging", 7200],
  ];
  return rows.map(([name, watts]) => {
    const power = Number(watts);
    const oneHour = power / 1000;
    const eightHours = oneHour * 8;
    const monthly = eightHours * 30 * 0.12;
    return [String(name), `${fmt(power, 0)} W`, `${fmt(oneHour, 3)} kWh`, `${fmt(eightHours, 2)} kWh`, `$${fmt(monthly, 2)}`];
  });
}

