function calculate(kind: Kind, mode: Mode, values: Values): Result {
  if (kind === "newtons") {
    if (mode === "force") {
      const force = values.mass * values.acceleration;
      return { label: "Force", value: `${fmt(force)} N`, detail: "Net force needed for this motion.", step: `F = m x a = ${values.mass} x ${values.acceleration} = ${fmt(force)} N`, cards: [{ label: "Mass", value: `${fmt(values.mass)} kg` }, { label: "Acceleration", value: `${fmt(values.acceleration)} m/s^2` }] };
    }
    if (mode === "mass") {
      const mass = values.force / values.acceleration;
      return { label: "Mass", value: `${fmt(mass)} kg`, detail: "Mass found by dividing force by acceleration.", step: `m = F / a = ${values.force} / ${values.acceleration} = ${fmt(mass)} kg`, cards: [{ label: "Force", value: `${fmt(values.force)} N` }, { label: "Acceleration", value: `${fmt(values.acceleration)} m/s^2` }] };
    }
    const acceleration = values.force / values.mass;
    return { label: "Acceleration", value: `${fmt(acceleration)} m/s^2`, detail: "Acceleration produced by the force on this mass.", step: `a = F / m = ${values.force} / ${values.mass} = ${fmt(acceleration)} m/s^2`, cards: [{ label: "Force", value: `${fmt(values.force)} N` }, { label: "Mass", value: `${fmt(values.mass)} kg` }] };
  }
  if (kind === "kinetic") {
    if (mode === "velocity") {
      const velocity = Math.sqrt((2 * values.energy) / values.mass);
      return { label: "Velocity", value: `${fmt(velocity)} m/s`, detail: "Speed needed to carry that kinetic energy.", step: `v = sqrt(2 x KE / m) = sqrt(2 x ${values.energy} / ${values.mass}) = ${fmt(velocity)} m/s`, cards: [{ label: "Energy", value: `${fmt(values.energy)} J` }, { label: "Mass", value: `${fmt(values.mass)} kg` }] };
    }
    const energy = 0.5 * values.mass * values.velocity * values.velocity;
    return { label: "Kinetic Energy", value: `${fmt(energy)} J`, detail: "Energy stored in the object's motion.", step: `KE = 1/2 x m x v^2 = 1/2 x ${values.mass} x ${values.velocity}^2 = ${fmt(energy)} J`, cards: [{ label: "Mass", value: `${fmt(values.mass)} kg` }, { label: "Velocity", value: `${fmt(values.velocity)} m/s` }] };
  }
  if (kind === "potential") {
    if (mode === "elastic") {
      const energy = 0.5 * values.spring * values.displacement * values.displacement;
      return { label: "Elastic Potential Energy", value: `${fmt(energy)} J`, detail: "Energy stored in the stretched or compressed spring.", step: `PE = 1/2 x k x x^2 = 1/2 x ${values.spring} x ${values.displacement}^2 = ${fmt(energy)} J`, cards: [{ label: "Spring constant", value: `${fmt(values.spring)} N/m` }, { label: "Displacement", value: `${fmt(values.displacement)} m` }] };
    }
    const energy = values.mass * values.gravity * values.height;
    return { label: "Gravitational Potential Energy", value: `${fmt(energy)} J`, detail: "Energy stored because of height in a gravitational field.", step: `PE = m x g x h = ${values.mass} x ${values.gravity} x ${values.height} = ${fmt(energy)} J`, cards: [{ label: "Mass", value: `${fmt(values.mass)} kg` }, { label: "Height", value: `${fmt(values.height)} m` }] };
  }
  if (kind === "workPower") {
    if (mode === "power") {
      const power = values.work / values.time;
      return { label: "Power", value: `${fmt(power)} W`, detail: `${fmt(power / 745.7, 4)} hp`, step: `P = W / t = ${values.work} / ${values.time} = ${fmt(power)} W`, cards: [{ label: "Horsepower", value: `${fmt(power / 745.7, 4)} hp` }, { label: "Energy", value: `${fmt(values.work / 3600000, 6)} kWh` }] };
    }
    if (mode === "energy") {
      const energy = values.power * values.time;
      return { label: "Energy", value: `${fmt(energy)} J`, detail: `${fmt(energy / 3600000, 6)} kWh`, step: `E = P x t = ${values.power} x ${values.time} = ${fmt(energy)} J`, cards: [{ label: "kWh", value: fmt(energy / 3600000, 6) }, { label: "Power", value: `${fmt(values.power)} W` }] };
    }
    const radians = (values.angle * Math.PI) / 180;
    const work = values.force * values.distance * Math.cos(radians);
    return { label: "Work", value: `${fmt(work)} J`, detail: "Mechanical work along the direction of motion.", step: `W = F x d x cos(theta) = ${values.force} x ${values.distance} x cos(${values.angle}) = ${fmt(work)} J`, cards: [{ label: "kWh", value: fmt(work / 3600000, 6) }, { label: "Angle", value: `${fmt(values.angle)} deg` }] };
  }
  if (mode === "frequency") {
    const frequency = values.speed / values.wavelength;
    return { label: "Frequency", value: `${sci(frequency, 4)} Hz`, detail: "Cycles per second for this wave.", step: `f = v / lambda = ${values.speed} / ${values.wavelength} = ${sci(frequency, 4)} Hz`, cards: [{ label: "Wave speed", value: `${sci(values.speed)} m/s` }, { label: "Wavelength", value: `${sci(values.wavelength)} m` }] };
  }
  if (mode === "speed") {
    const speed = values.wavelength * values.frequency;
    return { label: "Wave Speed", value: `${sci(speed, 4)} m/s`, detail: "Distance traveled by the wave each second.", step: `v = lambda x f = ${values.wavelength} x ${values.frequency} = ${sci(speed, 4)} m/s`, cards: [{ label: "Wavelength", value: `${sci(values.wavelength)} m` }, { label: "Frequency", value: `${sci(values.frequency)} Hz` }] };
  }
  const wavelength = values.speed / values.frequency;
  return { label: "Wavelength", value: `${sci(wavelength, 4)} m`, detail: "Distance between matching points on the wave.", step: `lambda = v / f = ${values.speed} / ${values.frequency} = ${sci(wavelength, 4)} m`, cards: [{ label: "Nanometers", value: `${sci(wavelength * 1e9, 4)} nm` }, { label: "Frequency", value: `${sci(values.frequency)} Hz` }] };
}

function ScienceTable({ table }: { table: PageConfig["table"] }) {
  return (
    <section className="mb-8">
      <h2 className="text-2xl font-bold text-foreground mb-4">{table.title}</h2>
      <div className="overflow-x-auto rounded-2xl border border-border bg-card shadow-sm">
        <table className="w-full text-sm">
          <thead className="bg-muted/70">
            <tr>{table.headers.map((header) => <th key={header} className="px-4 py-3 text-left font-bold text-foreground whitespace-nowrap">{header}</th>)}</tr>
          </thead>
          <tbody>
            {table.rows.map((row, index) => (
              <tr key={row.join("-")} className={index % 2 === 0 ? "bg-background" : "bg-muted/30"}>
                {row.map((cell, cellIndex) => <td key={`${cell}-${cellIndex}`} className="px-4 py-3 text-muted-foreground whitespace-nowrap">{cell}</td>)}
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </section>
  );
}

function LinkList({ title, items }: { title: string; items: Array<string | { label: string; href: string }> }) {
  return (
    <section className="bg-card border border-border rounded-2xl p-6 shadow-sm mb-8">
      <h2 className="text-2xl font-bold text-foreground mb-4">{title}</h2>
      <div className="flex flex-wrap gap-2">
        {items.map((item) => {
          const label = typeof item === "string" ? item : item.label;
          const href = typeof item === "string" ? undefined : item.href;
          const className = "rounded-full border border-border bg-muted/50 px-3 py-1.5 text-sm font-semibold text-muted-foreground hover:text-primary transition-colors";
          return href ? <a key={label} href={href} className={className}>{label}</a> : <span key={label} className={className}>{label}</span>;
        })}
      </div>
    </section>
  );
}

export function createScienceCalculatorPage(kind: Kind) {
  const config = CONFIGS[kind];
  const guide = getScienceGuide(config.path);

  function ScienceCalculatorPage() {
    const [mode, setMode] = useState(config.defaultMode);
    const [values, setValues] = useState<Values>(config.defaults);
    const currentMode = config.modes[mode];
    const result = useMemo(() => calculate(kind, mode, values), [mode, values]);

    const setValue = (key: string, value: number) => setValues((current) => ({ ...current, [key]: value }));

    return (
      <>
        <SEOHead
          title={guide?.title ?? config.title}
          description={guide?.description ?? config.description}
          canonical={config.path}
          keywords={guide?.keywords ?? config.keywords}
          category="Science"
          breadcrumbName={guide?.h1 ?? config.h1}
          schemaType="WebApplication"
          schemaApplicationCategory="UtilitiesApplication"
          faqs={guide?.faqs ?? config.faqs}
        />
        <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
          <div className="mb-8">
            <span className="text-xs font-semibold uppercase tracking-widest text-cyan-600 dark:text-cyan-400 bg-cyan-50 dark:bg-cyan-950/50 px-3 py-1 rounded-full mb-4 inline-block">Science</span>
            <h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">{guide?.h1 ?? config.h1}</h1>
            <p className="text-muted-foreground leading-relaxed">{guide?.description ?? config.description}</p>
          </div>
          <AdPlaceholder size="banner" className="mb-8" />
          <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8">
            <div className="mb-6">
              <label htmlFor={`${kind}-mode`} className="text-sm font-semibold text-foreground block mb-2">Mode</label>
              <select id={`${kind}-mode`} value={mode} onChange={(event) => setMode(event.target.value)} className={inputClass}>
                {Object.entries(config.modes).map(([key, option]) => <option key={key} value={key}>{option.label}</option>)}
              </select>
            </div>
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 mb-8">
              {currentMode.fields.map((field) => (
                <div key={field.key}>
                  <label htmlFor={`${kind}-${field.key}`} className="text-sm font-semibold text-foreground block mb-2">{field.label}</label>
                  <div className="grid grid-cols-[1fr_auto] gap-2">
                    <input id={`${kind}-${field.key}`} type="number" inputMode="decimal" value={values[field.key]} onChange={(event) => setValue(field.key, Number(event.target.value))} className={inputClass} />
                    <span className="px-3 py-2 rounded-xl border border-border bg-muted/50 text-sm font-bold text-muted-foreground flex items-center">{field.unit}</span>
                  </div>
                  {field.hint && <p className="text-xs text-muted-foreground mt-1">{field.hint}</p>}
                </div>
              ))}
            </div>
            <motion.div key={`${mode}-${Object.values(values).join("-")}`} initial={{ opacity: 0.75, y: 4 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.22 }}>
              <div className="bg-gradient-to-br from-cyan-500 to-blue-700 rounded-2xl p-6 text-center shadow-lg">
                <p className="text-xs font-semibold uppercase tracking-widest text-white/75 mb-1">{result.label}</p>
                <p className="text-4xl sm:text-5xl font-black text-white tracking-tight break-words" data-testid={`result-${kind}`}>{result.value}</p>
                <p className="text-sm text-white/80 mt-2">{result.detail}</p>
              </div>
              <div className="grid grid-cols-1 sm:grid-cols-2 gap-3 mt-4">
                {result.cards.map((card) => (
                  <div key={card.label} className="bg-accent/50 border border-border rounded-xl p-4">
                    <p className="text-xs font-bold uppercase tracking-wide text-muted-foreground">{card.label}</p>
                    <p className="text-lg font-black text-foreground">{card.value}</p>
                  </div>
                ))}
              </div>
              <div className="mt-4 bg-accent/60 border border-border rounded-xl p-4">
                <p className="text-xs font-bold uppercase tracking-wide text-muted-foreground mb-2">Step by step</p>
                <p className="text-sm text-foreground" data-testid={`result-steps-${kind}`}>{result.step}</p>
              </div>
            </motion.div>
          </section>
          <ShareButton />
          <ScienceTable table={config.table} />
          {guide ? (
            <ScienceExpandedContent guide={guide} />
          ) : (
            <section className="mb-8 space-y-6">
              {config.h2s.map((section) => (
                <div key={section.title}>
                  <h2 className="text-2xl font-bold text-foreground mb-2">{section.title}</h2>
                  <p className="text-muted-foreground leading-relaxed">{section.body}</p>
                </div>
              ))}
            </section>
          )}
          <ScienceRelatedCalculatorCards title="Related Calculators" items={config.related} fallbackCategory="Science" />
          <section className="mb-8">
            <h2 className="text-2xl font-bold text-foreground mb-4">{guide?.faqHeading ?? "Frequently Asked Questions"}</h2>
            <div className="space-y-3">{(guide?.faqs ?? config.faqs).map((faq) => <FAQItem key={faq.q} q={faq.q} a={faq.a} />)}</div>
          </section>
          <AdPlaceholder size="rectangle" className="mx-auto mb-8" />
        </main>
      </>
    );
  }

  return ScienceCalculatorPage;
}
